module top_module(ReadData1, ReadData2, opCode, funct3, one);input [31:0] ReadData1, ReadData2;
	input [6:0] opCode;
	input [2:0] funct3;
	output one;

	reg one;

	always @(ReadData1 or ReadData2 or funct3)
		begin
			if(opCode == 7'b1100011)begin
				case(funct3)

					3'b001:begin
					one = (ReadData1 != ReadData2)? 1 : 0;
					end
				endcase
			end
			else one = 0;
		end
endmodule
